#![allow(clippy::unwrap_used, clippy::expect_used, clippy::doc_markdown)]

/// Verify at test time that no LLM API key env var names appear in src/.
///
/// This is an in-process grep over the source tree, not a shell call, so it
/// works offline without any network access.
#[test]
fn acceptance_ac8() {
    let forbidden = &["ANTHROPIC_API_KEY", "OPENAI_API_KEY", "GEMINI_API_KEY"];

    // Walk src/ relative to the manifest dir (CARGO_MANIFEST_DIR is set by cargo).
    let manifest_dir = std::env::var("CARGO_MANIFEST_DIR")
        .expect("CARGO_MANIFEST_DIR must be set by cargo during test");
    let src_dir = std::path::Path::new(&manifest_dir).join("src");

    for entry in walkdir(&src_dir) {
        let path = entry;
        if path.extension().and_then(|e| e.to_str()) != Some("rs") {
            continue;
        }
        let content = std::fs::read_to_string(&path)
            .unwrap_or_default();
        for &key in forbidden {
            assert!(
                !content.contains(key),
                "Found forbidden API key reference `{key}` in {}",
                path.display()
            );
        }
    }
}

/// Minimal recursive directory walker that yields file paths.
fn walkdir(root: &std::path::Path) -> Vec<std::path::PathBuf> {
    let mut out = Vec::new();
    if root.is_dir() {
        if let Ok(entries) = std::fs::read_dir(root) {
            for entry in entries.flatten() {
                let p = entry.path();
                if p.is_dir() {
                    out.extend(walkdir(&p));
                } else {
                    out.push(p);
                }
            }
        }
    }
    out
}
